ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?street_name ?neighborhood (COUNT(?employee_id_a) AS ?agg) WHERE {
  ?e a :Employees .
  ?b a :Branches .
  ?e p:hasbranches ?b .
  ?b p:branch_id ?branch_id_g .
  ?b p:street_name ?street_name .
  ?b p:neighborhood ?neighborhood .
  ?e p:employee_id ?employee_id_a .
}
GROUP BY ?branch_id_g ?street_name ?neighborhood
ORDER BY DESC(?agg) }
  component: { SELECT ?street_name (COUNT(?employee_id_a) AS ?agg) WHERE {
  ?e a :Employees .
  ?b a :Branches .
  ?e p:hasbranches ?b .
  ?b p:branch_id ?branch_id_g .
  ?b p:street_name ?street_name .
  ?e p:employee_id ?employee_id_a .
}
GROUP BY ?branch_id_g ?street_name
ORDER BY DESC(?agg) }
  component_2: { SELECT ?neighborhood (COUNT(?employee_id_a) AS ?agg) WHERE {
  ?e a :Employees .
  ?b a :Branches .
  ?e p:hasbranches ?b .
  ?b p:branch_id ?branch_id_g .
  ?b p:neighborhood ?neighborhood .
  ?e p:employee_id ?employee_id_a .
}
GROUP BY ?branch_id_g ?neighborhood
ORDER BY DESC(?agg) }
}

PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?neighborhood WHERE {
  ?branches a :Branches .
  ?branches p:neighborhood ?neighborhood .
  ?branches p:branch_manager ?branch_manager_f .
  FILTER(STR(?branch_manager_f) = "David Black")
} }
  component_2: { SELECT ?street_name WHERE {
  ?branches a :Branches .
  ?branches p:street_name ?street_name .
  ?branches p:branch_manager ?branch_manager_f .
  FILTER(STR(?branch_manager_f) = "David Black")
} }
  full: { SELECT ?street_name ?neighborhood WHERE {
  ?branches a :Branches .
  ?branches p:street_name ?street_name .
  ?branches p:neighborhood ?neighborhood .
  ?branches p:branch_manager ?branch_manager_f .
  FILTER(STR(?branch_manager_f) = "David Black")
} }
}
